"use client";

import { useEffect } from "react";
import { motion } from "framer-motion";
import { ChevronRight, Download } from "lucide-react";
import { profile } from "@/data/profile";

export default function Hero() {
  // Inject Unicorn Studio script and hide branding
  useEffect(() => {
    const embedScript = document.createElement("script");
    embedScript.type = "text/javascript";
    embedScript.textContent = `
      !function(){
        if(!window.UnicornStudio){
          window.UnicornStudio={isInitialized:!1};
          var i=document.createElement("script");
          i.src="https://cdn.jsdelivr.net/gh/hiunicornstudio/unicornstudio.js@v1.4.33/dist/unicornStudio.umd.js";
          i.onload=function(){
            window.UnicornStudio.isInitialized||(UnicornStudio.init(),window.UnicornStudio.isInitialized=!0)
          };
          (document.head || document.body).appendChild(i)
        }
      }();
    `;
    document.head.appendChild(embedScript);

    const style = document.createElement("style");
    style.textContent = `
      [data-us-project] { position: relative !important; overflow: hidden !important; }
      [data-us-project] canvas { will-change: transform; }
      [data-us-project] * { pointer-events: none !important; }
      [data-us-project] a[href*="unicorn"],
      [data-us-project] button[title*="unicorn"],
      [data-us-project] div[title*="Made with"],
      [data-us-project] .unicorn-brand,
      [data-us-project] [class*="brand"],
      [data-us-project] [class*="credit"],
      [data-us-project] [class*="watermark"] {
        display: none !important;
      }
    `;
    document.head.appendChild(style);

    // Use MutationObserver instead of setInterval — only fires on actual DOM changes
    let observer: MutationObserver | null = null;

    const removeBrandingNodes = (root: Element) => {
      root.querySelectorAll("a, button, div").forEach((el) => {
        const text = (el.textContent || "").toLowerCase();
        if (text.includes("made with") || text.includes("unicorn")) {
          el.remove();
        }
      });
    };

    // Watch the section itself so we catch the project div when Unicorn injects it
    const sectionEl = document.getElementById("home");
    if (sectionEl) {
      observer = new MutationObserver(() => {
        const projectDiv = sectionEl.querySelector("[data-us-project]");
        if (projectDiv) removeBrandingNodes(projectDiv);
      });
      observer.observe(sectionEl, { childList: true, subtree: true });
    }

    return () => {
      observer?.disconnect();
      document.head.removeChild(embedScript);
      document.head.removeChild(style);
    };
  }, []);

  const handleScroll = (href: string) => {
    const element = document.querySelector(href);
    if (element) element.scrollIntoView({ behavior: "smooth" });
  };

  const firstName = profile.name.split(" ")[0];

  return (
    <section
      id="home"
      className="relative min-h-screen overflow-hidden bg-black"
    >
      {/* Unicorn Studio background — desktop only */}
      <div className="absolute inset-0 w-full h-full hidden lg:block">
        <div
          data-us-project="whwOGlfJ5Rz2rHaEUgHl"
          style={{ width: "100%", height: "100%", minHeight: "100vh" }}
        />
      </div>

      {/* Stars background — mobile only */}
      <div
        className="absolute inset-0 w-full h-full lg:hidden"
        style={{
          backgroundImage: `
            radial-gradient(1px 1px at 20% 30%, white, transparent),
            radial-gradient(1px 1px at 60% 70%, white, transparent),
            radial-gradient(1px 1px at 50% 50%, white, transparent),
            radial-gradient(1px 1px at 80% 10%, white, transparent),
            radial-gradient(1px 1px at 90% 60%, white, transparent),
            radial-gradient(1px 1px at 33% 80%, white, transparent),
            radial-gradient(1px 1px at 15% 60%, white, transparent),
            radial-gradient(1px 1px at 70% 40%, white, transparent)
          `,
          backgroundSize:
            "200% 200%, 180% 180%, 250% 250%, 220% 220%, 190% 190%, 240% 240%, 210% 210%, 230% 230%",
          opacity: 0.3,
        }}
      />

      {/* Corner frame accents */}
      <div className="absolute top-0 left-0 w-8 h-8 lg:w-12 lg:h-12 border-t-2 border-l-2 border-white/30 z-20 pointer-events-none" />
      <div className="absolute top-0 right-0 w-8 h-8 lg:w-12 lg:h-12 border-t-2 border-r-2 border-white/30 z-20 pointer-events-none" />
      <div className="absolute left-0 w-8 h-8 lg:w-12 lg:h-12 border-b-2 border-l-2 border-white/30 z-20 pointer-events-none" style={{ bottom: "5vh" }} />
      <div className="absolute right-0 w-8 h-8 lg:w-12 lg:h-12 border-b-2 border-r-2 border-white/30 z-20 pointer-events-none" style={{ bottom: "5vh" }} />

      {/* Main content */}
      <div
        className="relative z-10 flex min-h-screen items-center"
        style={{ paddingTop: "80px" }}
      >
        <div className="container mx-auto px-6 lg:px-16 lg:ml-[8%]">
          <div className="max-w-xl relative">

            {/* Status badge */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4 }}
              className="flex items-center gap-2 mb-4 opacity-70"
            >
              <div className="w-8 h-px bg-white" />
              <span className="text-white text-[10px] font-mono tracking-widest uppercase">
                Available for work
              </span>
              <div className="flex-1 h-px bg-white/30" />
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-75" />
                <span className="relative inline-flex rounded-full h-2 w-2 bg-white" />
              </span>
            </motion.div>

            {/* Name / Title */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.1 }}
              className="relative mb-3 lg:mb-5"
            >
              {/* Dither accent bar */}
              <div
                className="hidden lg:block absolute -left-3 top-0 bottom-0 w-1 opacity-40"
                style={{
                  backgroundImage: `
                    repeating-linear-gradient(0deg, transparent 0px, transparent 1px, white 1px, white 2px),
                    repeating-linear-gradient(90deg, transparent 0px, transparent 1px, white 1px, white 2px)
                  `,
                  backgroundSize: "3px 3px",
                }}
              />
              <h1
                className="text-3xl lg:text-6xl font-bold text-white leading-tight font-mono"
                style={{ letterSpacing: "0.08em" }}
              >
                HI, I&apos;M
                <span className="block mt-1 lg:mt-2 bg-gradient-to-r from-white to-white/60 bg-clip-text text-transparent">
                  {firstName.toUpperCase()}
                </span>
              </h1>
            </motion.div>

            {/* Role */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.2 }}
              className="hidden lg:flex gap-1 mb-3 opacity-40"
            >
              {Array.from({ length: 40 }).map((_, i) => (
                <div key={i} className="w-0.5 h-0.5 bg-white rounded-full" />
              ))}
            </motion.div>

            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.25 }}
              className="font-mono text-sm lg:text-base text-white/60 mb-4 tracking-widest uppercase"
            >
              &gt; {profile.role}_
            </motion.div>

            {/* Bio */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.3 }}
              className="relative mb-6 lg:mb-8"
            >
              <p className="text-xs lg:text-sm text-gray-400 leading-relaxed font-mono opacity-80 max-w-md">
                {profile.bio}
              </p>
              <div
                className="hidden lg:block absolute -right-4 top-1/2 w-3 h-3 border border-white/30"
                style={{ transform: "translateY(-50%)" }}
              >
                <div
                  className="absolute top-1/2 left-1/2 w-1 h-1 bg-white/30"
                  style={{ transform: "translate(-50%, -50%)" }}
                />
              </div>
            </motion.div>

            {/* CTA Buttons */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: 0.4 }}
              className="flex flex-col sm:flex-row gap-3 sm:gap-4"
            >
              <button
                onClick={() => handleScroll("#projects")}
                className="relative px-6 py-2.5 bg-transparent text-white font-mono text-xs lg:text-sm border border-white hover:bg-white hover:text-black transition-all duration-200 group flex items-center gap-2"
              >
                <span className="hidden lg:block absolute -top-1 -left-1 w-2 h-2 border-t border-l border-white opacity-0 group-hover:opacity-100 transition-opacity" />
                <span className="hidden lg:block absolute -bottom-1 -right-1 w-2 h-2 border-b border-r border-white opacity-0 group-hover:opacity-100 transition-opacity" />
                VIEW PROJECTS
                <ChevronRight className="w-4 h-4" />
              </button>

              <button
                onClick={() => window.open("/resume.pdf", "_blank")}
                className="relative px-6 py-2.5 bg-transparent border border-white/50 text-white/80 font-mono text-xs lg:text-sm hover:border-white hover:text-white hover:bg-white/5 transition-all duration-200 flex items-center gap-2"
              >
                <Download className="w-4 h-4" />
                DOWNLOAD CV
              </button>
            </motion.div>

            {/* Bottom notation */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.4, delay: 0.55 }}
              className="hidden lg:flex items-center gap-2 mt-6 opacity-30"
            >
              <span className="text-white text-[9px] font-mono">
                {profile.location.toUpperCase()}
              </span>
              <div className="flex-1 h-px bg-white" />
              <span className="text-white text-[9px] font-mono">
                {profile.socials.github.replace("https://", "")}
              </span>
            </motion.div>
          </div>
        </div>
      </div>

      {/* Bottom status bar */}
      <div
        className="absolute left-0 right-0 z-20 border-t border-white/20 bg-black/70"
        style={{ bottom: "5vh" }}
      >
        <div className="container mx-auto px-4 lg:px-8 py-2 lg:py-3 flex items-center justify-between">
          <div className="flex items-center gap-3 lg:gap-6 text-[8px] lg:text-[9px] font-mono text-white/50">
            <span className="hidden lg:inline">SYSTEM.ACTIVE</span>
            <span className="lg:hidden">SYS.ACT</span>
            <div className="hidden lg:flex gap-1 items-end">
              {Array.from({ length: 8 }).map((_, i) => (
                <div
                  key={i}
                  className="w-1 bg-white/30"
                  style={{ height: `${(i % 3) * 4 + 4}px` }}
                />
              ))}
            </div>
            <span>V1.0.0</span>
          </div>

          {/* Scroll indicator */}
          <div className="flex flex-col items-center gap-1">
            <span className="text-[8px] font-mono text-white/40 tracking-widest">
              SCROLL
            </span>
            <motion.div
              animate={{ y: [0, 6, 0] }}
              transition={{ repeat: Infinity, duration: 1.5, ease: "easeInOut" }}
              className="w-px h-6 bg-gradient-to-b from-white/60 to-transparent"
            />
          </div>

          <div className="flex items-center gap-2 lg:gap-4 text-[8px] lg:text-[9px] font-mono text-white/50">
            <span className="hidden lg:inline">◐ RENDERING</span>
            <div className="flex gap-1">
              <div className="w-1 h-1 bg-white/60 rounded-full animate-pulse" />
              <div
                className="w-1 h-1 bg-white/40 rounded-full animate-pulse"
                style={{ animationDelay: "0.2s" }}
              />
              <div
                className="w-1 h-1 bg-white/20 rounded-full animate-pulse"
                style={{ animationDelay: "0.4s" }}
              />
            </div>
            <span className="hidden lg:inline">FRAME: ∞</span>
          </div>
        </div>
      </div>
    </section>
  );
}
